export function getPatternTranslate(properties, size, translate) {
    var patternSize = size[0];
    if (properties.width == patternSize) {
        return translate;
    }
    var patternSize = translate.map(function(d, i) {
        if (d == 0) {
            return 0;
        }
        var s = parseFloat(d);
        var quo = patternSize / s || 1; //if pattern size is greater than properties.width
        return properties.width / quo;
    });
    return patternSize;
}
export function applyEffect(element, options) {
    let { effect, config = {}, chartObj } = options;
    if (!effect && chartObj) {
        effect = getChartEffect(config, chartObj);
    }

    element
        .selectAll(
            '*:not(text):not(span):not(b):not(strong):not(i):not(em):not(mark):not(small):not(del):not(ins):not(sub):not(sup):not(.expandable):not(.zc-expandable):not(.minorTicks):not(.domain):not(.zc-connector-line)'
        )
        .filter(function() {
            return !this.childElementCount;
        })
        .style('filter', effect);
}

export function getChartEffect(config, chartObj) {
    let effect = config.useChartEffect !== false && chartObj.filterEffectsID;
    return effect ? `url(${chartObj.defsLocation}#${effect})` : null;
}
